import{_ as r,o as a,c,e as l}from"./app-def54fd2.js";const i="/assets/image-20230910192917095-12009a5e.png",t={},e=l('<h1 id="mysql-varchar与char" tabindex="-1"><a class="header-anchor" href="#mysql-varchar与char" aria-hidden="true">#</a> MySQL-varchar与char</h1><p><img src="'+i+'" alt="image-20230910192917095"></p><p><strong>如何选择：</strong></p><ul><li>字符串长度固定或者差别不大，选择char类型。</li><li>字符串长度差别较大，选择varchar类型。</li></ul><p><strong>相同点：</strong></p><ul><li>长度代表的是字符长度（其它类型都是代表字节长度）：varchar(7)、char(7) 代表的都是最多可以存储 7 个字符。</li></ul><p><strong>varchar（最多能存放的字符个数为 65532）：</strong></p><ul><li>可变长字符串，长度是可变的。</li><li>插入的数据是多长，就按照多长来存储。</li><li>时间换空间：长度不固定，存取慢，不占据多余的空间。</li></ul><p><strong>char（最多能存放的字符个数为 255，和编码无关）：</strong></p><ul><li>定长字符串，长度是固定的。</li><li>插入数据的长度小于 char 的固定长度时，则用空格填充。</li><li>空间换时间：长度固定，存取速度比 varchar 快，会占据多余的空间。</li></ul>',10),s=[e];function h(o,n){return a(),c("div",null,s)}const p=r(t,[["render",h],["__file","MySQL-varchar与char.html.vue"]]);export{p as default};
